// Script Continued Below
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
(function executeRule(current, previous /*null when async*/) {
	// 07.07.20: Tasker 2.5.0 Patch 1 Hotfix 2 Madrid

	// STRY0066883 RJ - discoverd the Task sys_id is avaialable at the start of insert.
	// this logic was moved to the front of the process to create the tree very early instead of at the end.

	// RAJ 2020.02.11  STRY0059160
	// if Parent is empty, then create the Tree Object
	if(!current.parent){
		var gr_Task_Create_Tree = new GlideRecord('x_153465_discovert_task_tree');
		gr_Task_Create_Tree.initialize();
		// the current object has the sys_id befoer insert.
		gr_Task_Create_Tree.u_task_ref = current.sys_id;
		gr_Task_Create_Tree.insert();

		// When a new task is created, we are creating a new tree reference.
		// the Top task needs a reference to the tree object created.
		// and the tree object needs a reference to the task.
		// This is not needed, b/c we are doing this before insert.
		//current.setWorkflow(false);

		current.u_task_tree = gr_Task_Create_Tree.sys_id;

		// STRY0051139 - allow customer to use the script associated with this to set key values in the system
		// ships with the defalut setting current.taskernumber = current.u_task_tree.u_shared_task_label + '-' + current.getDisplayValue('primary_assignee');
		// this logic is moved into a seperate object created just to set this value
		//var taskerNM = new TaskerDisplayValueConfiguration();
		//current.taskernumber = taskerNM.setTaskerNumber(current);
	}


})(current, previous);
